class Solution {
public:
    int countGoodStrings(int low, int high, int zero, int one) {
        const int MOD = 1e9 + 7;
        long long res = 0;
        for (int len = low; len <= high; ++len) {
            res += (pow(2, len, MOD) - 1) * (pow(2, len - 1, MOD) - 1) % MOD;
        }
        return res;
    }
};
